class TreeNode
{
    public int Val;
    public TreeNode Left, Right;
    public TreeNode(int val) { Val = val; }
}

class Program
{
    static void Inorder(TreeNode node, List<int> result)
    {
        if (node == null) return;
        Inorder(node.Left, result);
        result.Add(node.Val);
        Inorder(node.Right, result);
    }

    static void Preorder(TreeNode node, List<int> result)
    {
        if (node == null) return;
        result.Add(node.Val);
        Preorder(node.Left, result);
        Preorder(node.Right, result);
    }

    static void Main()
    {
        TreeNode root = new TreeNode(4);
        root.Left = new TreeNode(2);
        root.Right = new TreeNode(6);
        root.Left.Left = new TreeNode(1);
        root.Left.Right = new TreeNode(3);

        var inList = new List<int>();
        Inorder(root, inList);
        Console.WriteLine(String.Join(", ", inList)); // 1, 2, 3, 4, 6

        var preList = new List<int>();
        Preorder(root, preList);
        Console.WriteLine(String.Join(", ", preList)); // 4, 2, 1, 3, 6
    }
}

