class TreeNode
{
    public int Val;
    public TreeNode Left, Right;
    public TreeNode(int val) { Val = val; }
}

class Program
{
    static int MaxDepth(TreeNode node)
    {
        if (node == null) return 0;
        return 1 + Math.Max(MaxDepth(node.Left), MaxDepth(node.Right));
    }

    static bool IsBalanced(TreeNode node)
    {
        if (node == null) return true;
        int diff = Math.Abs(MaxDepth(node.Left) - MaxDepth(node.Right));
        return diff <= 1 && IsBalanced(node.Left) && IsBalanced(node.Right);
    }

    static void Main()
    {
        TreeNode root = new TreeNode(1);
        root.Left = new TreeNode(2);
        root.Right = new TreeNode(3);
        root.Left.Left = new TreeNode(4);
        root.Left.Left.Left = new TreeNode(5);

        Console.WriteLine(MaxDepth(root));      // 4
        Console.WriteLine(IsBalanced(root));    // False
    }
}

